#include <iostream>
using namespace std;

// Base class
class Animal {
public:
    string name;

    Animal(string n) : name(n) {}

    // Virtual method for polymorphism
    virtual void speak() {
        cout << name << " makes a sound" << endl;
    }
};

// Derived class
class Dog : public Animal {
public:
    Dog(string n) : Animal(n) {}

    // Override base class method
    void speak() override {
        cout << name << " says: Woof! Woof!" << endl;
    }
};

// Another derived class
class Cat : public Animal {
public:
    Cat(string n) : Animal(n) {}

    void speak() override {
        cout << name << " says: Meow!" << endl;
    }
};

int main() {
    Dog dog("Buddy");
    Cat cat("Whiskers");

    dog.speak();  // Output: Buddy says: Woof! Woof!
    cat.speak();  // Output: Whiskers says: Meow!

    return 0;
}

#include <iostream>
using namespace std;

// Base class (Abstract concept)
class Shape {
protected:
    string color;
public:
    Shape(string c) : color(c) {}

    // Pure virtual function - makes Shape abstract
    virtual double area() = 0;

    virtual void display() {
        cout << "Color: " << color << ", Area: " << area() << endl;
    }

    virtual ~Shape() {}
};

// Derived class: Circle
class Circle : public Shape {
private:
    double radius;
public:
    Circle(string c, double r) : Shape(c), radius(r) {}

    double area() override {
        return 3.14159 * radius * radius;
    }
};

// Derived class: Rectangle
class Rectangle : public Shape {
private:
    double length, width;
public:
    Rectangle(string c, double l, double w) : Shape(c), length(l), width(w) {}

    double area() override {
        return length * width;
    }
};

int main() {
    // Array of base class pointers - achieves polymorphism
    Shape* shapes[3];

    shapes[0] = new Circle("Red", 5.0);
    shapes[1] = new Rectangle("Blue", 4.0, 6.0);
    shapes[2] = new Circle("Green", 3.0);

    for (int i = 0; i < 3; i++) {
        shapes[i]->display();
    }

    // Clean up
    for (int i = 0; i < 3; i++) {
        delete shapes[i];
    }

    return 0;
}

#include <iostream>
#include <string>
using namespace std;

// Base class
class Employee {
protected:
    string name;
    int id;
    double salary;
public:
    Employee(string n, int i, double s) : name(n), id(i), salary(s) {}

    virtual void calculateBonus() = 0;

    virtual void display() {
        cout << "ID: " << id << ", Name: " << name << ", Salary: $" << salary;
    }

    virtual ~Employee() {}
};

// First level derived class
class Manager : public Employee {
private:
    int teamSize;
public:
    Manager(string n, int i, double s, int ts) : Employee(n, i, s), teamSize(ts) {}

    void calculateBonus() override {
        double bonus = salary * 0.15 + (teamSize * 100);
        cout << ", Bonus: $" << bonus << endl;
    }
};

// Second level derived class from Manager
class SeniorManager : public Manager {
private:
    int projects;
public:
    SeniorManager(string n, int i, double s, int ts, int p) 
        : Manager(n, i, s, ts), projects(p) {}

    void calculateBonus() override {
        double bonus = salary * 0.25 + (teamSize * 150) + (projects * 500);
        cout << ", Bonus: $" << bonus << endl;
    }
};

// Another branch of inheritance
class Developer : public Employee {
private:
    string language;
public:
    Developer(string n, int i, double s, string lang) : Employee(n, i, s), language(lang) {}

    void calculateBonus() override {
        double bonus = salary * 0.10;
        cout << ", Bonus: $" << bonus << endl;
    }
};

int main() {
    Employee* employees[4];

    employees[0] = new Manager("Alice", 101, 80000, 10);
    employees[1] = new Developer("Bob", 102, 60000, "Python");
    employees[2] = new SeniorManager("Charlie", 103, 120000, 25, 5);
    employees[3] = new Developer("Diana", 104, 70000, "C++");

    cout << "=== Employee Bonus Calculation ===" << endl;
    for (int i = 0; i < 4; i++) {
        employees[i]->display();
        employees[i]->calculateBonus();
    }

    // Clean up
    for (int i = 0; i < 4; i++) {
        delete employees[i];
    }

    return 0;
}
